'use client';
import { useState, useEffect } from 'react';
import Link from 'next/link';
import { Plus, Eye, Edit, Trash2, Users, Loader2 } from 'lucide-react';
import { supabase, Memorial } from '@/lib/supabase';

export default function FamilyDashboard() {
    const [memorials, setMemorials] = useState<Memorial[]>([]);
    const [loading, setLoading] = useState(true);
    const [userId, setUserId] = useState<string | null>(null);

    useEffect(() => {
        const uid = localStorage.getItem('user-id');
        setUserId(uid);
        if (uid) loadMemorials(uid);
    }, []);

    const loadMemorials = async (uid: string) => {
        setLoading(true);
        const { data, error } = await supabase
            .from('memorials')
            .select('*')
            .eq('user_id', uid)
            .eq('mode', 'family')
            .order('updated_at', { ascending: false });

        if (!error) setMemorials(data || []);
        setLoading(false);
    };

    const handleCreate = () => {
        window.location.href = '/create?mode=family';
    };

    const deleteMemorial = async (id: string) => {
        if (!confirm('Delete this memorial?')) return;
        await supabase.from('memorials').delete().eq('id', id);
        if (userId) loadMemorials(userId);
    };

    return (
        <div className="min-h-screen bg-gradient-to-br from-terracotta/5 via-ivory to-terracotta/10">
            <div className="bg-white border-b border-sand/30 shadow-sm">
                <div className="max-w-7xl mx-auto px-6 py-6">
                    <div className="flex items-center justify-between">
                        <div>
                            <h1 className="font-serif text-4xl text-charcoal mb-2">Family Memorials</h1>
                            <p className="text-charcoal/60">Your family memorial dashboard</p>
                        </div>
                        <button onClick={handleCreate} className="px-6 py-3 rounded-xl font-semibold flex items-center gap-2 bg-gradient-to-r from-terracotta to-terracotta/90 hover:shadow-lg text-ivory">
                            <Plus size={20} />
                            Create Memorial
                        </button>
                    </div>
                </div>
            </div>

            <div className="max-w-7xl mx-auto px-6 py-12">
                {loading ? (
                    <div className="text-center py-20">
                        <Loader2 size={48} className="text-terracotta animate-spin mx-auto mb-4" />
                    </div>
                ) : memorials.length === 0 ? (
                    <div className="text-center py-20">
                        <div className="w-24 h-24 bg-terracotta/10 rounded-full flex items-center justify-center mx-auto mb-6">
                            <Users size={48} className="text-terracotta" />
                        </div>
                        <h2 className="font-serif text-3xl text-charcoal mb-3">No Family Memorials Yet</h2>
                        <button onClick={handleCreate} className="inline-flex items-center gap-2 px-6 py-3 bg-terracotta hover:bg-terracotta/90 text-ivory rounded-xl font-semibold">
                            <Plus size={20} />
                            Create First Memorial
                        </button>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {memorials.map((memorial) => (
                            <div key={memorial.id} className="bg-white rounded-xl shadow-sm border border-sand/30 overflow-hidden">
                                <div className="relative h-48 bg-gradient-to-br from-terracotta/10 to-terracotta/20">
                                    {memorial.profile_photo_url ? (
                                        <img src={memorial.profile_photo_url} alt={memorial.full_name || ''} className="w-full h-full object-cover" />
                                    ) : (
                                        <div className="w-full h-full flex items-center justify-center">
                                            <Users size={64} className="text-charcoal/20" />
                                        </div>
                                    )}
                                </div>
                                <div className="p-6">
                                    <h3 className="font-serif text-2xl text-charcoal mb-4">{memorial.full_name || 'Untitled'}</h3>
                                    <div className="flex gap-2">
                                        <Link href={`/person/${memorial.id}`} className="flex-1 py-2 px-3 bg-terracotta/10 hover:bg-terracotta/20 text-terracotta rounded-lg font-medium text-center">
                                            <Eye size={16} className="inline mr-1" />
                                            View
                                        </Link>
                                        <Link href={`/create?id=${memorial.id}`} className="flex-1 py-2 px-3 bg-sage/10 hover:bg-sage/20 text-sage rounded-lg font-medium text-center">
                                            <Edit size={16} className="inline mr-1" />
                                            Edit
                                        </Link>
                                        <button onClick={() => deleteMemorial(memorial.id)} className="py-2 px-3 bg-red-50 hover:bg-red-100 text-red-600 rounded-lg">
                                            <Trash2 size={16} />
                                        </button>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
    );
}